import { createStore } from 'vuex'
import { getUserInfo } from '@/api/user' 
import { publicRequest } from '@/utils/request'
import router from '@/router'
import { showToast } from '@/components/ToastMessage'
import request from '@/utils/request'

// Token 相关常量
const TOKEN_CONFIG = {
  // 有效期配置
  NORMAL_EXPIRATION_TIME: 7200 * 1000, // 普通登录时token有效期2小时
  REMEMBER_EXPIRATION_TIME: 7 * 24 * 3600 * 1000, // 记住我时token有效期7天
  REFRESH_INTERVAL: 20 * 60 * 1000, // 刷新间隔20分钟
  REFRESH_THRESHOLD: 30 * 60 * 1000, // 刷新阈值30分钟

  // 存储键名配置
  STORAGE_KEYS: {
    ACCESS_TOKEN: 'access_token',
    REFRESH_TOKEN: 'refresh_token',
    EXPIRATION: 'token_expiration',
    REMEMBER_ME: 'remember_me'
  }
}

let refreshInterval = null
let isRefreshingToken = false
let refreshSubscribers = []

// Token 刷新订阅机制
const addRefreshSubscriber = (callback) => {
  refreshSubscribers.push(callback)
}

const onTokenRefreshed = (token) => {
  refreshSubscribers.forEach(callback => callback(token))
  refreshSubscribers = []
}

/**
 * 短信验证码场
 * @enum {string}
 */
export const SMS_SCENE = {
  REGISTER: 'register',
  LOGIN: 'login',
  RESET_PASSWORD: 'reset_password',
  CHANGE_PHONE: 'change_phone'
}

/**
 * Vuex Store 配置
 * @type {import('vuex').StoreOptions}
 */
export default createStore({
  state: {
    userInfo: null,
    isAuthenticated: false,
    accessToken: null,
    refreshToken: null,
    tokenExpiration: null,
    userPhone: null,
    userId: null,
    userAvatar: null,
    rememberMe: false,
    isHandlingExpiration: false
  },

  getters: {
    getFullMediaUrl: () => (path) => {
      if (!path) return '/default-avatar.png'
      if (path.startsWith('http')) return path
      return `${import.meta.env.VITE_API_URL}${path}`
    },
    getUserInfo: state => state.userInfo,
    isAuthenticated: state => state.isAuthenticated,
    getAccessToken: state => state.accessToken,
    getUserPhone: state => state.userPhone,
    getUserId: state => state.userId,
    getUserAvatar: (state) => {
      // 优先使用 state 中的头像，然后是 localStorage 中的头像
      const avatar = state.userAvatar || 
                    state.userInfo?.avatar || 
                    state.userInfo?.data?.avatar_url || 
                    localStorage.getItem('user_avatar')

      if (!avatar) return require('@/assets/images/default-avatar.png')
      if (avatar.startsWith('http')) return avatar
      return `${process.env.VUE_APP_API_URL}${avatar}`
    },
    wechatLoginStatus: state => state.wechatLoginStatus,
    wechatLoginError: state => state.wechatLoginError
  },

  mutations: {
    SET_AUTH_DATA(state, { tokens, remember, phone, expiration }) {
      if (tokens) {
        // 更新 state
        state.accessToken = tokens.access
        state.refreshToken = tokens.refresh
        state.tokenExpiration = expiration
        state.isAuthenticated = true
        state.rememberMe = remember
        state.userPhone = phone

        // 更新 localStorage
        const { STORAGE_KEYS } = TOKEN_CONFIG
        localStorage.setItem(STORAGE_KEYS.ACCESS_TOKEN, tokens.access)
        localStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN, tokens.refresh)
        localStorage.setItem(STORAGE_KEYS.EXPIRATION, expiration.toString())
        localStorage.setItem(STORAGE_KEYS.REMEMBER_ME, remember.toString())
        localStorage.setItem('account_phone', phone)

        // 调试日志
        if (process.env.NODE_ENV === 'development') {
          console.log('Auth state updated:', {
            isAuthenticated: state.isAuthenticated,
            expiration: new Date(expiration).toLocaleString(),
            phone: state.userPhone
          })
        }
      }
    },

    SET_USER_INFO(state, userInfo) {
      try {
        // 保存原有的手机号
        const accountPhone = state.userPhone

        // 处理数据结构
        const userData = userInfo
        // 尝试从不同位置获取头像，优先使用新头像
        const avatar = userData.avatar || userData.data?.avatar_url || localStorage.getItem('user_avatar')

        // 更新状态
        state.userInfo = {
          ...state.userInfo,
          ...userData,
          accountPhone,
          profile: {
            ...(state.userInfo?.profile || {}),
            avatar  // 保存头像信息
          }
        }

        // 更新头像状态
        if (avatar) {
          state.userAvatar = avatar
          // 持久化存储头像路径到 localStorage
          localStorage.setItem('user_avatar', avatar)
        }

        // 调试日志
        if (process.env.NODE_ENV === 'development') {
          console.log('User state updated:', {
            userInfo: state.userInfo,
            avatar: state.userAvatar,
            savedAvatar: localStorage.getItem('user_avatar'),
            fullAvatarUrl: avatar ? `${process.env.VUE_APP_API_URL}${avatar}` : null
          })
        }
      } catch (error) {
        console.error('Error updating user info:', error)
      }
    },

    CLEAR_AUTH(state) {
      // 保存当前头像
      const currentAvatar = state.userAvatar || localStorage.getItem('user_avatar')

      // 清除状态
      state.userInfo = null
      state.isAuthenticated = false
      state.accessToken = null
      state.refreshToken = null
      state.tokenExpiration = null
      state.userPhone = null
      state.userId = null
      state.rememberMe = false

      // 不清除头像状态
      // state.userAvatar = null

      // 清除定时器
      if (refreshInterval) {
        clearInterval(refreshInterval)
        refreshInterval = null
      }

      // 清除 TOKEN_CONFIG 中定义的存储项
      const { STORAGE_KEYS } = TOKEN_CONFIG
      Object.values(STORAGE_KEYS).forEach(key => {
        localStorage.removeItem(key)
      })

      // 清除其他相关存储项，但保留头像
      const additionalKeys = [
        'account_phone',
        'redirectPath',
        'user_id'
        // 不清除 'user_avatar'
      ]

      // 从 localStorage 和 sessionStorage 都清除
      additionalKeys.forEach(key => {
        localStorage.removeItem(key)
        sessionStorage.removeItem(key)
      })

      // 如果有头像，保存回 localStorage
      if (currentAvatar) {
        localStorage.setItem('user_avatar', currentAvatar)
      }

      if (process.env.NODE_ENV === 'development') {
        console.log('Auth state cleared, avatar preserved:', currentAvatar)
      }
    }
  },
  actions: {
    async checkAuth({ dispatch, commit }) {
      try {
        const { STORAGE_KEYS } = TOKEN_CONFIG
        const token = localStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN)
        const refreshToken = localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN)
        const expiration = localStorage.getItem(STORAGE_KEYS.EXPIRATION)
        const rememberMe = localStorage.getItem(STORAGE_KEYS.REMEMBER_ME) === 'true'
        const phone = localStorage.getItem('account_phone')
        const savedAvatar = localStorage.getItem('user_avatar')

        // 调试日志
        if (process.env.NODE_ENV === 'development') {
          console.log('Checking auth state:', {
            hasToken: !!token,
            hasRefreshToken: !!refreshToken,
            expiration: expiration ? new Date(parseInt(expiration)).toLocaleString() : null,
            rememberMe,
            phone,
            savedAvatar
          })
        }

        if (!token || !refreshToken || !expiration) {
          console.log('Missing auth data:', { token: !!token, refreshToken: !!refreshToken, expiration: !!expiration })
          commit('CLEAR_AUTH')
          return false
        }

        const now = Date.now()
        const expirationTime = parseInt(expiration)

        // 如果 token 未过期直接使用
        if (now < expirationTime) {
          // 先恢复基本认证信息
          commit('SET_AUTH_DATA', {
            tokens: {
              access: token,
              refresh: refreshToken
            },
            expiration: expirationTime,
            remember: rememberMe,
            phone
          })

          try {
            // 立即获取最新的用户信息
            const userInfo = await dispatch('fetchUserInfo')
            if (userInfo) {
              commit('SET_USER_INFO', {
                ...userInfo,
                avatar: userInfo.avatar || savedAvatar  // 使用新头像或保存的头像
              })
            }
          } catch (error) {
            console.error('Failed to fetch user info:', error)
            // 如果获取失败，使用保存的头像
            if (savedAvatar) {
              commit('SET_USER_INFO', {
                avatar: savedAvatar
              })
            }
          }

          return true
        }

        // 如果 token 已过期，尝试刷新
        try {
          const newToken = await dispatch('refreshToken')
          if (newToken) {
            // Token 刷新成功后，重新获取用户信息
            await dispatch('fetchUserInfo')
            return true
          }
        } catch (error) {
          console.error('Token refresh failed:', error)
        }

        commit('CLEAR_AUTH')
        return false
      } catch (error) {
        console.error('Check auth error:', error)
        commit('CLEAR_AUTH')
        return false
      }
    },

    async initAuth({ commit, dispatch }) {
      try {
        // 清除可能存在的旧定时器
        if (refreshInterval) {
          clearInterval(refreshInterval)
          refreshInterval = null
        }

        const result = await dispatch('checkAuth')

        if (result) {
          // 设置新的定时器
          refreshInterval = setInterval(async () => {
            if (process.env.NODE_ENV === 'development') {
              console.log('Scheduled token check running...')
            }
            await dispatch('checkAuth')
          }, TOKEN_CONFIG.REFRESH_INTERVAL)

          if (process.env.NODE_ENV === 'development') {
            console.log('Token check interval set:', TOKEN_CONFIG.REFRESH_INTERVAL / 1000, 'seconds')
          }
        }

        return result
      } catch (error) {
        console.error('Init auth error:', error)
        commit('CLEAR_AUTH')
        return false
      }
    },

    async fetchUserInfo({ commit }) {
      try {
        const response = await request({
          url: '/api/v1/users/profile/basic/',
          method: 'get'
        })

        if (!response.data) {
          throw new Error('获取用户信息失败：无数据返回')
        }

        const userData = response.data
        console.log('Fetched user data:', userData)

        // 更新用户信息，使用正确的数据结构
        commit('SET_USER_INFO', {
          ...userData,
          data: {
            avatar_url: userData.avatar
          }
        })

        // 调试日志
        if (process.env.NODE_ENV === 'development') {
          console.log('User info updated:', {
            userData,
            avatar: userData.avatar,
            fullAvatarUrl: `${process.env.VUE_APP_API_URL}${userData.avatar}`
          })
        }

        return userData
      } catch (error) {
        console.error('Fetch user info failed:', error)
        throw error
      }
    },

    async loginWithPassword({ commit, dispatch }, { tokens, remember, phone }) {
      try {
        // 根据记住我选项设置过期时间
        const expiration = remember ? 
          Date.now() + TOKEN_CONFIG.REMEMBER_EXPIRATION_TIME :
          Date.now() + TOKEN_CONFIG.NORMAL_EXPIRATION_TIME

        // 更新 state
        commit('SET_AUTH_DATA', {
          tokens,
          remember,
          phone,
          expiration
        })

        // 调试日志
        if (process.env.NODE_ENV === 'development') {
          console.log('Auth data updated:', {
            tokens,
            expiration: new Date(expiration).toLocaleString(),
            remember,
            phone
          })
        }

        // 尝试获取用户信息
        try {
          const userInfo = await dispatch('fetchUserInfo')
          if (userInfo) {
            commit('SET_USER_INFO', userInfo)
          }
        } catch (error) {
          console.error('Failed to fetch user info:', error)
        }

        return true
      } catch (error) {
        console.error('Login failed:', error)
        commit('CLEAR_AUTH')
        throw error
      }
    },

    async refreshToken({ commit, state }) {
      if (isRefreshingToken) {
        return new Promise((resolve) => {
          addRefreshSubscriber(token => {
            resolve(token)
          })
        })
      }

      try {
        isRefreshingToken = true
        const refreshToken = state.refreshToken || localStorage.getItem('refresh_token')

        if (!refreshToken) {
          throw new Error('No refresh token available')
        }

        const response = await publicRequest({
          url: '/v1/auth/token/refresh/',
          method: 'post',
          data: { refresh: refreshToken }
        })

        if (!response.data?.access || response.data?.code !== 200) {
          throw new Error(response.data?.message || 'Invalid refresh response')
        }

        const newExpirationTime = new Date().getTime() + (
          state.rememberMe ? 
          TOKEN_CONFIG.REMEMBER_EXPIRATION_TIME : 
          TOKEN_CONFIG.NORMAL_EXPIRATION_TIME
        )

        // 立即更新 state 和 localStorage 的 tokens
        commit('SET_AUTH_DATA', {
          tokens: {
            access: response.data.access,
            refresh: response.data.refresh  // 使用新的 refresh token
          },
          expirationTime: newExpirationTime,
          remember: state.rememberMe
        })

        onTokenRefreshed(response.data.access)
        return response.data.access

      } catch (error) {
        console.error('Token refresh failed:', error.response?.data || error.message)

        if (error.response?.data?.detail?.includes('黑单') || 
            error.response?.status === 400) {
          await this.dispatch('handleTokenExpired')
        } else {
          commit('CLEAR_AUTH')
        }
        throw error
      } finally {
        isRefreshingToken = false
      }
    },
    async logout({ commit, state }) {
      try {
        const refreshToken = state.refreshToken || localStorage.getItem('refresh_token')

        if (refreshToken) {
          try {
            await publicRequest({
              url: '/v1/auth/logout/',
              method: 'post',
              headers: {
                'Authorization': `Bearer ${state.accessToken || localStorage.getItem('access_token')}`
              },
              data: { 
                refresh: refreshToken 
              }
            })
            console.log('Logout successful')
          } catch (error) {
            console.error('Logout API error:', error)
          }
        }
      } finally {
        commit('CLEAR_AUTH')
        router.push('/login')
      }
    },

    async loginWithToken({ commit, dispatch }, token) {
      try {
        const expirationTime = new Date().getTime() + TOKEN_CONFIG.EXPIRATION_TIME

        commit('SET_AUTH_DATA', {
          tokens: { access: token },
          expirationTime,
          remember: false
        })

        await dispatch('fetchUserInfo')
        return true
      } catch (error) {
        commit('CLEAR_AUTH')
        throw error
      }
    },

    async handleTokenExpired({ commit, state }) {
      if (state.isHandlingExpiration) {
        return
      }

      state.isHandlingExpiration = true

      try {
        const currentPath = router.currentRoute.value.fullPath
        const isLoginPage = currentPath === '/login'

        // 先清除认证信息
        commit('CLEAR_AUTH')

        // 保存重定向路径（如果不是登录页）
        if (!isLoginPage) {
          localStorage.setItem('redirectPath', currentPath)
          showToast('登录已过期，请重新登录', 'warning')

          await router.push({
            path: '/login',
            query: { 
              redirect: currentPath,
              source: 'expired'
            }
          })
        }
      } catch (error) {
        console.error('Error during token expiration handling:', error)
      } finally {
        state.isHandlingExpiration = false
      }
    }
  }
})
